let filterSliders = document.querySelectorAll(".filter-slider")

filterSliders.forEach(slider => {
    const rangeSlider = slider.querySelector(`.range-slider`)
    const rangeInput0 = slider.querySelector(`.range-slider__input1`)
    const rangeInput1 = slider.querySelector(`.range-slider__input2`)
    const rangeInputs = [rangeInput0, rangeInput1]

    let startValue1 = +slider.getAttribute("data-start")
    let startValue2 = +slider.getAttribute("data-start2")
    let min = +slider.getAttribute("data-min")
    let max = +slider.getAttribute("data-max")

    if (rangeSlider) {
        noUiSlider.create(rangeSlider, {
            start: [startValue1, startValue2],
            connect: true,
            step: 1,
            range: {
                'min': min,
                'max': max
            }
        });
    }
    if (rangeSlider) {
        rangeSlider.noUiSlider.on('update', function(values, handle) {
            rangeInputs[handle].value = Math.round(values[handle])
        })
        rangeInputs.forEach((el, index) => {
            el.addEventListener('change', (e) => {
                setRangeSlider(index, e.currentTarget.value)
            })
        })
    }
    const setRangeSlider = (i, value) => {
        let array = [null, null];
        array[i] = value;

        rangeSlider.noUiSlider.set(array);
    };
})

$(".cart-table__check-all input").change(function () {
    let checked = $(this).prop("checked")
    $(".cart-table__check-all input").removeClass("_semi-check")

    $(".cart-table__check input").each(function (index, el){
        $(el).prop("checked",checked)
    });

})

$(".cart-table__check input").change(function () {
    let cartItemCount = $(".cart-table__check input").length
    let cartSelectedCount = checkCheckedCount()


    $(".cart-table__check-all input").prop("checked",false)
    if(cartSelectedCount < cartItemCount){
        $(".cart-table__check-all input").addClass("_semi-check")
    }
    if(cartSelectedCount === 0){
        $(".cart-table__check-all input").removeClass("_semi-check")
    }
    if(cartSelectedCount === cartItemCount){
        $(".cart-table__check-all input").removeClass("_semi-check")
        $(".cart-table__check-all input").prop("checked",true)
    }
})

function checkCheckedCount() {
    return $(".cart-table__check input:checked").length
}

$(`[name="buyerType"]`).change(function () {
    let val = $(this).attr("data-value")
    $(".order-buyer__content").removeClass("_active")
    $(`.order-buyer__content[data-content="${val}"]`).addClass("_active")
})
