$("._toggle-menu").click(function () {
    $(".header").toggleClass("_open")
    $("body").toggleClass("fixed-body")
})

$("._toggle-catalog").click(function () {
    $(".header").toggleClass("_open-catalog")
    $("body").toggleClass("fixed-body")
    $(window).scrollTop(0);
})

$(".menu-item").mouseover(function () {
    $(".menu-item").removeClass("_show")
    $(this).addClass("_show")
})

$("._add-to-cart").click(function () {
    $(".header").addClass("_show-cart")
    setTimeout(()=>{
        $(".header").removeClass("_show-cart")
    },10000)
})

